const express = require('express');
const app = express();
const path = require('path');

app.use(express.static('public'));

app.get('/about', (req, res) => {
  res.send('About Us');
});

// 404 handler
app.use((req, res) => {
  res.status(404).send('404 - Page Not Found');
});

app.listen(3000, () => console.log('Server running'));
